#include <stdio.h>

void print_size(int arr[]) {
    /* arr has decayed to pointer */
    printf("Inside function: sizeof(arr) = %zu\n", sizeof(arr));
    /* 8 on 64-bit (pointer size, NOT array size) */
}

int main(void) {
    int arr[5] = {1, 2, 3, 4, 5};

    /* No decay: sizeof gives array size */
    printf("sizeof(arr) = %zu\n", sizeof(arr)); /* 20 */

    /* Decay: array name becomes pointer */
    int *p = arr;  /* arr decays to &arr[0] */
    printf("*p = %d\n", *p); /* 1 */

    /* No decay: &arr gives pointer to entire array */
    int (*ap)[5] = &arr;  /* pointer to array of 5 ints */
    printf("sizeof(*ap) = %zu\n", sizeof(*ap)); /* 20 */

    /* Decay in function call */
    print_size(arr); /* arr decays to pointer */

    /* arr and &arr have same address but different types */
    printf("arr    = %p\n", (void *)arr);    /* pointer to first element */
    printf("&arr   = %p\n", (void *)&arr);   /* pointer to whole array */
    printf("Same address? %d\n", (void *)arr == (void *)&arr); /* 1 (yes) */
    /* But: arr+1 advances by sizeof(int); &arr+1 advances by sizeof(arr) */

    return 0;
}

