#include <stdio.h>
#include <string.h>

int main(void) {
    /* String literal: pointer to read-only memory */
    const char *literal = "hello";  /* use const for safety */
    printf("%s, sizeof(literal)=%zu\n", literal, sizeof(literal)); /* 8 (ptr) */
    /* literal[0] = 'H';  // UB! Do NOT modify string literals */

    /* Char array: modifiable copy */
    char array[] = "hello";
    printf("%s, sizeof(array)=%zu\n", array, sizeof(array)); /* 6 (5+null) */
    array[0] = 'H';  /* OK -- this is a modifiable copy */
    printf("Modified: %s\n", array); /* Hello */

    /* Pointer can be reassigned; array cannot */
    literal = "world";  /* OK -- pointer now points elsewhere */
    /* array = "world";  // ERROR: array name is not assignable */

    /* String literals may be shared by the compiler */
    const char *s1 = "hello";
    const char *s2 = "hello";
    printf("Same address? %d\n", s1 == s2); /* may be 1 (shared) */

    /* Array is always a unique copy */
    char a1[] = "hello";
    char a2[] = "hello";
    printf("Same address? %d\n", a1 == a2); /* always 0 (different) */

    return 0;
}

