int main(void) {
    /* Null terminator included automatically */
    char s[] = "hello";
    printf("strlen = %zu\n", strlen(s));  /* 5 */
    printf("sizeof = %zu\n", sizeof(s));  /* 6 */
    printf("last byte = %d\n", s[5]);     /* 0 (null terminator) */

    /* Manual string construction -- must add null terminator! */
    char manual[6];
    manual[0] = 'h';
    manual[1] = 'e';
    manual[2] = 'l';
    manual[3] = 'l';
    manual[4] = 'o';
    manual[5] = '\0';  /* CRITICAL: without this, strlen etc. are UB */
    printf("manual: %s\n", manual); /* hello */

    /* What happens without null terminator */
    char bad[5] = {'h', 'e', 'l', 'l', 'o'}; /* NO null terminator */
    printf("strlen = %zu\n", strlen(bad)); /* UNDEFINED: reads past array */
    /* May print garbage after "hello", may crash */

    /* Buffer sizing: always +1 for null terminator */
    char buf[11]; /* can hold 10 chars + null */
    strncpy(buf, "0123456789", sizeof(buf) - 1);
    buf[sizeof(buf) - 1] = '\0'; /* ensure termination */
    printf("%s\n", buf);

    return 0;
}

