int main(void) {
    /* strlen */
    printf("strlen(\"hello\") = %zu\n", strlen("hello")); /* 5 */

    /* strcpy */
    char buf[20];
    strcpy(buf, "hello");
    printf("strcpy: %s\n", buf); /* hello */

    /* strncpy -- CAUTION: may not null-terminate */
    char safe[6];
    strncpy(safe, "hello world", sizeof(safe) - 1);
    safe[sizeof(safe) - 1] = '\0'; /* always null-terminate */
    printf("strncpy: %s\n", safe); /* hello */

