    char greeting[30] = "Hello";
    strcat(greeting, ", ");
    strcat(greeting, "World!");
    printf("strcat: %s\n", greeting); /* Hello, World! */

    /* strcmp */
    printf("strcmp(\"abc\",\"abd\") = %d\n", strcmp("abc", "abd")); /* < 0 */
    printf("strcmp(\"abc\",\"abc\") = %d\n", strcmp("abc", "abc")); /* 0 */
    printf("strcmp(\"abd\",\"abc\") = %d\n", strcmp("abd", "abc")); /* > 0 */

    /* strstr */
    const char *text = "Hello, World!";
    const char *found = strstr(text, "World");
    if (found) {
        printf("Found at offset %td\n", found - text); /* 7 */
    }

    /* strstr not found */
    if (strstr(text, "xyz") == NULL) {
        printf("'xyz' not found\n");
    }

