#include <stdio.h>
#include <string.h>

void reverse_string(char *s) {
    int left = 0;
    int right = (int)strlen(s) - 1;
    while (left < right) {
        char temp = s[left];
        s[left] = s[right];
        s[right] = temp;
        left++;
        right--;
    }
}

/* Recursive version */
void reverse_recursive(char *s, int left, int right) {
    if (left >= right) return;
    char temp = s[left];
    s[left] = s[right];
    s[right] = temp;
    reverse_recursive(s, left + 1, right - 1);
}

int main(void) {
    char s1[] = "hello";
    reverse_string(s1);
    printf("%s\n", s1); /* olleh */

    char s2[] = "abcdef";
    reverse_recursive(s2, 0, (int)strlen(s2) - 1);
    printf("%s\n", s2); /* fedcba */

    char s3[] = "a";
    reverse_string(s3);
    printf("%s\n", s3); /* a (single char) */

    char s4[] = "";
    reverse_string(s4);
    printf("'%s'\n", s4); /* '' (empty string) */

    return 0;
}

