/* Basic palindrome check */
int is_palindrome(const char *s) {
    int left = 0;
    int right = (int)strlen(s) - 1;
    while (left < right) {
        if (s[left] != s[right]) return 0;
        left++;
        right--;
    }
    return 1;
}

/* Case-insensitive, ignoring non-alphanumeric */
int is_palindrome_smart(const char *s) {
    int left = 0;
    int right = (int)strlen(s) - 1;
    while (left < right) {
        while (left < right && !isalnum(s[left])) left++;
        while (left < right && !isalnum(s[right])) right--;
        if (tolower(s[left]) != tolower(s[right])) return 0;
        left++;
        right--;
    }
    return 1;
}

int main(void) {
    printf("racecar: %d\n", is_palindrome("racecar"));     /* 1 */
    printf("hello:   %d\n", is_palindrome("hello"));       /* 0 */
    printf("a:       %d\n", is_palindrome("a"));           /* 1 */
    printf("empty:   %d\n", is_palindrome(""));            /* 1 */

    /* Smart check */
    printf("'A man, a plan, a canal: Panama': %d\n",
           is_palindrome_smart("A man, a plan, a canal: Panama")); /* 1 */
    printf("'race a car': %d\n",
           is_palindrome_smart("race a car")); /* 0 */

    return 0;
}

