#include <stdio.h>
#include <ctype.h>

int main(void) {
    /* Classification */
    printf("isalpha('A') = %d\n", isalpha('A') != 0);  /* 1 */
    printf("isdigit('5') = %d\n", isdigit('5') != 0);  /* 1 */
    printf("isspace(' ') = %d\n", isspace(' ') != 0);  /* 1 */
    printf("isalnum('_') = %d\n", isalnum('_') != 0);  /* 0 */

    /* Conversion */
    printf("toupper('a') = %c\n", toupper('a'));  /* A */
    printf("tolower('Z') = %c\n", tolower('Z'));  /* z */
    printf("toupper('1') = %c\n", toupper('1'));  /* 1 (unchanged) */

    /* Practical: count types in a string */
    const char *s = "Hello, World! 123";
    int letters = 0, digits = 0, spaces = 0, others = 0;
    for (int i = 0; s[i]; i++) {
        unsigned char c = (unsigned char)s[i];
        if (isalpha(c)) letters++;
        else if (isdigit(c)) digits++;
        else if (isspace(c)) spaces++;
        else others++;
    }
    printf("letters=%d digits=%d spaces=%d others=%d\n",
           letters, digits, spaces, others);
    /* letters=10 digits=3 spaces=2 others=2 */

    /* Convert string to uppercase */
    char buf[] = "Hello World";
    for (int i = 0; buf[i]; i++) {
        buf[i] = (char)toupper((unsigned char)buf[i]);
    }
    printf("%s\n", buf); /* HELLO WORLD */

    return 0;
}

