    strcpy(names[2], "Dave");  /* Replace string */
    for (int i = 0; i < 3; i++) {
        printf("%s\n", names[i]);
    }

    /* Sorting an array of string pointers */
    const char *words[] = {"banana", "apple", "cherry"};
    int wn = 3;
    for (int i = 0; i < wn - 1; i++) {
        for (int j = i + 1; j < wn; j++) {
            if (strcmp(words[i], words[j]) > 0) {
                const char *temp = words[i];
                words[i] = words[j];
                words[j] = temp;
            }
        }
    }
    for (int i = 0; i < wn; i++) printf("%s ", words[i]);
    printf("\n"); /* apple banana cherry */

    return 0;
}

