#include <stdio.h>

void print_table(int rows, int cols) {
    /* VLA: size determined at runtime */
    int table[rows][cols];

    /* Initialize */
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            table[i][j] = i * cols + j;
        }
    }

    /* Print */
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%4d", table[i][j]);
        }
        printf("\n");
    }
}

int main(void) {
    int n = 5;
    int arr[n];  /* VLA */

    for (int i = 0; i < n; i++) {
        arr[i] = i * i;
    }
    for (int i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n"); /* 0 1 4 9 16 */

    /* VLA for 2D array with runtime dimensions */
    print_table(3, 4);

    /* sizeof VLA is evaluated at runtime */
    printf("sizeof(arr) = %zu\n", sizeof(arr)); /* 20 */

    return 0;
}

