#include <stdio.h>

#define ARRAY_SIZE(arr) (sizeof(arr) / sizeof((arr)[0]))

/* This does NOT work -- arr has decayed to a pointer */
void bad_print(int arr[]) {
    /* sizeof(arr) is sizeof(int*), NOT the array size */
    int n = sizeof(arr) / sizeof(arr[0]);
    printf("bad count: %d\n", n); /* likely 2 on 64-bit (8/4) */
}

/* Correct: pass the size separately */
void good_print(const int *arr, int n) {
    for (int i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");
}

int main(void) {
    int arr[] = {10, 20, 30, 40, 50};
    int n = ARRAY_SIZE(arr);
    printf("Element count: %d\n", n); /* 5 */

    bad_print(arr);       /* wrong count */
    good_print(arr, n);   /* correct: 10 20 30 40 50 */

    /* Works for any type */
    double d[] = {1.1, 2.2, 3.3};
    printf("doubles: %zu\n", ARRAY_SIZE(d)); /* 3 */

    char s[] = "hello";
    printf("chars (including null): %zu\n", ARRAY_SIZE(s)); /* 6 */

    return 0;
}

