/* Check if two strings are anagrams */
int are_anagrams(const char *s1, const char *s2) {
    int freq[256] = {0};
    for (int i = 0; s1[i]; i++) freq[(unsigned char)s1[i]]++;
    for (int i = 0; s2[i]; i++) freq[(unsigned char)s2[i]]--;
    for (int i = 0; i < 256; i++) {
        if (freq[i] != 0) return 0;
    }
    return 1;
}

/* Find first non-repeating character */
char first_unique(const char *s) {
    int freq[256] = {0};
    for (int i = 0; s[i]; i++) freq[(unsigned char)s[i]]++;
    for (int i = 0; s[i]; i++) {
        if (freq[(unsigned char)s[i]] == 1) return s[i];
    }
    return '\0'; /* all characters repeat */
}

/* Simple atoi implementation */
int my_atoi(const char *s) {
    int sign = 1, result = 0, i = 0;
    while (isspace((unsigned char)s[i])) i++;
    if (s[i] == '-' || s[i] == '+') {
        sign = (s[i] == '-') ? -1 : 1;
        i++;
    }
    while (isdigit((unsigned char)s[i])) {
        result = result * 10 + (s[i] - '0');
        i++;
    }
    return sign * result;
}

/* Check if s2 is a rotation of s1 */
int is_rotation(const char *s1, const char *s2) {
    size_t len = strlen(s1);
    if (len != strlen(s2)) return 0;
    char doubled[200];
    snprintf(doubled, sizeof(doubled), "%s%s", s1, s1);
    return strstr(doubled, s2) != NULL;
}

int main(void) {
    printf("anagram: %d\n", are_anagrams("listen", "silent")); /* 1 */
    printf("first unique in 'aabbc': %c\n", first_unique("aabbc")); /* c */
    printf("my_atoi('  -123') = %d\n", my_atoi("  -123")); /* -123 */
    printf("rotation: %d\n", is_rotation("abcde", "cdeab")); /* 1 */
    return 0;
}

